            'tag': 'display_notification',
            'params': {
                'title': 'Portal Access Already Exists',
                'message': 'This applicant already has portal access.',
                'type': 'warning',
            }
        }

def action_generate_portal_credentials(self):
    """Generate (or refresh) a temporary portal access token for this applicant."""
    self.ensure_one()
    token = self.env['hr.applicant.portal.token'].generate_for_applicant(self)
    if not token:
        return {
            'type': 'ir.actions.client',
            'tag': 'display_notification',
            'params': {
                'title': 'Cannot Generate Credentials',
                'message': 'The applicant needs a valid email address to generate portal credentials.',
                'type': 'warning',
                'sticky': False,
            },
        }
    base_url = self.env['ir.config_parameter'].sudo().get_param('web.base.url')
    magic_link = f"{base_url}/recruitment/portal/login/{token.token}"
    return {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'title': 'Portal Credentials Generated',
            'message': (
                f"Login: {token.portal_user_id.login}\n"
                f"Password: {token.temp_password}\n"
                f"Link: {magic_link}"
            ),
            'type': 'success',
            'sticky': True,
        },
    }

@api.onchange('job_id')
def _onchange_job_id(self):
    """Copy interviewers from job position when job is selected."""
    if self.job_id and self.job_id.interviewer_ids:
        self.interviewer_ids = [(6, 0, self.job_id.interviewer_ids.ids)]

@api.model_create_multi
def create(self, vals_list):
    applicants = super().create(vals_list)

