# ---- Magic-link login ----

@http.route('/recruitment/portal/login/<string:token>', type='http', auth='public', website=True)
def portal_magic_link_login(self, token, **kw):
    """Authenticate the candidate from a one-click magic link and redirect to their application."""
    import logging
    _logger = logging.getLogger(__name__)

    Token = request.env['hr.applicant.portal.token'].sudo()
    token_rec = Token.search([('token', '=', token)], limit=1)

    if not token_rec:
        _logger.warning("Portal login failed: Token '%s...' not found in database", token[:8])
        return request.render('hr_recruitment_enhanced.portal_token_invalid', {
            'error_detail': 'Token not found'
        })

    if token_rec.is_expired:
        _logger.info(
            "Portal login failed: Token for applicant %s expired at %s",
            token_rec.applicant_id.id, token_rec.expiry
        )
        return request.render('hr_recruitment_enhanced.portal_token_invalid', {
            'error_detail': 'Token expired',
            'applicant': token_rec.applicant_id,
        })

    if not token_rec.portal_user_id:
        _logger.error("Portal login failed: Token %s has no portal_user_id", token_rec.id)
        return request.render('hr_recruitment_enhanced.portal_token_invalid', {
            'error_detail': 'No portal user associated'
        })

    user = token_rec.portal_user_id
    temp_password = token_rec.temp_password

    if not temp_password:
        _logger.error("Portal login failed: Token %s has no temp_password", token_rec.id)
        return request.render('hr_recruitment_enhanced.portal_token_invalid', {
            'error_detail': 'Invalid credentials'
        })

    # Check if user is already authenticated as the correct portal user
    if request.env.uid == user.id:
        _logger.info(
            "User %s already authenticated, redirecting to application %s",
            user.login, token_rec.applicant_id.id
        )
        return request.redirect('/my/application/%s' % token_rec.applicant_id.id)

    # Attempt authentication
    try:
        uid = request.session.authenticate(request.db, user.login, temp_password)
        if not uid:
            _logger.warning(
                "Portal login failed: Authentication returned None for user %s", user.login
            )
            return request.render('hr_recruitment_enhanced.portal_token_invalid', {
                'error_detail': 'Authentication failed'
            })

        _logger.info(
            "Portal login successful: User %s authenticated for applicant %s",
            user.login, token_rec.applicant_id.id
        )
        return request.redirect('/my/application/%s' % token_rec.applicant_id.id)

    except Exception as e:
        _logger.error(
            "Portal login exception for user %s: %s", user.login, str(e), exc_info=True
        )
        return request.render('hr_recruitment_enhanced.portal_token_invalid', {
            'error_detail': 'System error during authentication'
        })

