class ApplicantPortal(CustomerPortal):

    def _prepare_home_portal_values(self, counters):
        values = super()._prepare_home_portal_values(counters)
        if 'applicant_count' in counters:
            # ir.model.access gives portal users read on hr.applicant;
            # ir.rule (portal_security.xml) restricts them to their own partner.
            applicant_count = request.env['hr.applicant'].search_count([
                ('partner_id', '=', request.env.user.partner_id.id)
            ]) if request.env.user.partner_id else 0
            values['applicant_count'] = applicant_count
        return values

    def _is_recruitment_only_user(self):
        """Check if the current user is a recruitment-only portal user (candidate)."""
        user = request.env.user

        # Must be a portal user, not internal
        if user.has_group('base.group_user'):
            return False

        # Must have at least one application
        if not user.partner_id:
            return False

        applicant_count = request.env['hr.applicant'].search_count([
            ('partner_id', '=', user.partner_id.id)
        ])

        if applicant_count == 0:
            return False

        # Check if user has access to other portal features (orders, invoices, tickets, etc.)
        # by checking for records in common portal models
        partner_id = user.partner_id.id

        has_sales = request.env['sale.order'].search_count([
            ('partner_id', 'child_of', partner_id)
        ], limit=1) > 0

        has_invoices = request.env['account.move'].search_count([
            ('partner_id', 'child_of', partner_id),
            ('move_type', 'in', ['out_invoice', 'out_refund'])
        ], limit=1) > 0

        # If user has applications but no other portal content, they're recruitment-only
        return not (has_sales or has_invoices)

    @http.route(['/my', '/my/home'], type='http', auth="user", website=True)
    def home(self, **kw):
        """Override portal home to redirect recruitment-only users to their applications."""
        if self._is_recruitment_only_user():
            return request.redirect('/my/applications')
        return super().home(**kw)

